* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: "Hiragino Kaku Gothic ProN", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  -webkit-font-smoothing: antialiased;
  background: #f8f8fb;
  color: #1a1a1a;
}

.dashboard {
  max-width: 1200px;
  margin: 0 auto;
  padding: 32px 24px;
}

/* Header */
.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 32px;
}

.header-title {
  font-size: 20px;
  font-weight: 700;
  color: #1a1a1a;
}

.header-actions {
  display: flex;
  align-items: center;
  gap: 12px;
}

.sync-status {
  font-size: 12px;
  color: #626264;
}

.sync-button {
  background: #0031d8;
  color: #ffffff;
  border: none;
  border-radius: 6px;
  padding: 8px 16px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s;
}

.sync-button:hover {
  background: #0028b0;
}

.sync-button:disabled {
  background: #c5d7fb;
  cursor: not-allowed;
}

/* Repository Bar */
.repo-bar {
  margin-bottom: 24px;
}

.repo-selector {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
}

.repo-select {
  flex: 1;
  padding: 8px 12px;
  border: 1px solid #e8e8eb;
  border-radius: 6px;
  font-size: 13px;
  background: #ffffff;
  color: #1a1a1a;
  cursor: pointer;
}

.repo-select:focus {
  outline: none;
  border-color: #0031d8;
}

.repo-add-button {
  background: none;
  border: 1px dashed #c5c5c8;
  border-radius: 6px;
  padding: 8px 14px;
  font-size: 13px;
  font-weight: 600;
  color: #626264;
  cursor: pointer;
  transition: all 0.15s;
  white-space: nowrap;
}

.repo-add-button:hover {
  border-color: #0031d8;
  color: #0031d8;
}

.repo-form {
  display: flex;
  gap: 8px;
  margin-bottom: 8px;
}

.repo-input {
  flex: 1;
  padding: 8px 12px;
  border: 1px solid #e8e8eb;
  border-radius: 6px;
  font-size: 13px;
  font-family: "SF Mono", "Fira Code", "Fira Mono", Menlo, monospace;
}

.repo-input:focus {
  outline: none;
  border-color: #0031d8;
}

.repo-tag-name {
  font-weight: 600;
  color: #1a1a1a;
}

.repo-tag-path {
  color: #626264;
  font-family: "SF Mono", "Fira Code", "Fira Mono", Menlo, monospace;
  font-size: 11px;
}

/* Repository Management */
.repo-manage {
  margin-top: 8px;
  background: #ffffff;
  border: 1px solid #e8e8eb;
  border-radius: 8px;
  overflow: hidden;
}

.repo-manage-header {
  padding: 10px 16px;
  background: #f8f8fb;
  border-bottom: 1px solid #e8e8eb;
}

.repo-manage-title {
  font-size: 12px;
  font-weight: 700;
  color: #626264;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.repo-manage-empty {
  padding: 16px;
  font-size: 13px;
  color: #626264;
}

.repo-manage-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 16px;
  border-bottom: 1px solid #f0f0f3;
}

.repo-manage-row:last-child {
  border-bottom: none;
}

.repo-manage-info {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}

.repo-manage-delete {
  background: none;
  border: 1px solid #d32f2f;
  border-radius: 4px;
  color: #d32f2f;
  font-size: 12px;
  font-weight: 600;
  padding: 4px 12px;
  cursor: pointer;
  white-space: nowrap;
  transition: all 0.15s;
}

.repo-manage-delete:hover {
  background: #d32f2f;
  color: #ffffff;
}

/* Section */
.section {
  margin-bottom: 32px;
}

.section-title {
  font-size: 14px;
  font-weight: 700;
  color: #1a1a1a;
  margin-bottom: 4px;
}

.section-subtitle {
  font-size: 12px;
  color: #626264;
  margin-bottom: 16px;
}

/* KPI Cards */
.kpi-row {
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: 16px;
  margin-bottom: 32px;
}

.kpi-card {
  background: #ffffff;
  border: 1px solid #e8e8eb;
  border-radius: 8px;
  padding: 20px;
}

.kpi-card--primary {
  background: #0031d8;
  border-color: #0031d8;
  color: #ffffff;
}

.kpi-label {
  font-size: 12px;
  color: #626264;
  margin-bottom: 8px;
  font-weight: 500;
}

.kpi-card--primary .kpi-label {
  color: rgba(255, 255, 255, 0.8);
}

.kpi-value {
  font-size: 36px;
  font-weight: 700;
  color: #1a1a1a;
  line-height: 1.1;
}

.kpi-card--primary .kpi-value {
  color: #ffffff;
  font-size: 48px;
}

.kpi-unit {
  font-size: 14px;
  font-weight: 400;
  margin-left: 2px;
}

/* Chart Container */
.chart-container {
  background: #ffffff;
  border: 1px solid #e8e8eb;
  border-radius: 8px;
  padding: 24px;
}

/* Session List */
.session-list {
  display: flex;
  flex-direction: column;
  gap: 1px;
  background: #e8e8eb;
  border: 1px solid #e8e8eb;
  border-radius: 8px;
