  grid-template-columns: 100px 1fr 100px 100px 100px 80px;
  align-items: center;
  gap: 16px;
}

.session-row--header {
  background: #f8f8fb;
  font-size: 11px;
  font-weight: 600;
  color: #626264;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  padding: 10px 20px;
}

.session-date {
  font-size: 13px;
  color: #626264;
}

.session-date-main {
  font-weight: 600;
  color: #1a1a1a;
}

.session-branch {
  font-family: "SF Mono", "Fira Code", "Fira Mono", Menlo, monospace;
  font-size: 12px;
  color: #1a1a1a;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.session-prompt {
  font-size: 12px;
  color: #626264;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  margin-top: 2px;
}

.session-lines {
  font-size: 13px;
  font-weight: 600;
  text-align: right;
}

.session-lines--ai {
  color: #0031d8;
}

.session-lines--human {
  color: #22a06b;
}

.session-lines--total {
  color: #1a1a1a;
}

.session-ratio {
  text-align: right;
}

.session-ratio-bar {
  height: 4px;
  border-radius: 2px;
  background: #22a06b;
  overflow: hidden;
  margin-bottom: 4px;
}

.session-ratio-fill {
  height: 100%;
  background: #0031d8;
  border-radius: 2px;
}

.session-ratio-text {
  font-size: 12px;
  font-weight: 600;
  color: #626264;
}

/* Agent Badge */
.agent-badge {
  display: inline-block;
  font-size: 11px;
  font-weight: 600;
  color: #0031d8;
  background: #e8f1fe;
  padding: 2px 8px;
  border-radius: 4px;
}

/* Footer / Meta */
.meta-info {
  font-size: 11px;
  color: #626264;
  margin-top: 8px;
  display: flex;
  gap: 16px;
}

/* Clickable session row */
.session-row--clickable {
  cursor: pointer;
  transition: background 0.1s;
}

.session-row--clickable:hover {
  background: #f8f8fb;
}

/* Expanded prompt */
.session-expanded-prompt {
  background: #f8f8fb;
  padding: 12px 20px 12px 136px;
  font-size: 13px;
  line-height: 1.6;
  color: #1a1a1a;
  white-space: pre-wrap;
  overflow-wrap: break-word;
  border-top: 1px solid #e8e8eb;
}

/* Empty state */
.empty-state {
  text-align: center;
  padding: 60px 20px;
  color: #626264;
  font-size: 14px;
}

